import numpy as np

class MultinomialNaiveBayes:
    def __init__(self, alpha: float = 1.0):
        self.alpha = alpha

    def fit(self, X: np.ndarray, y: np.ndarray) -> None:
        self.classes_ = np.unique(y)
        N, V = X.shape
        self.log_priors_ = np.array([np.log(np.sum(y == c) / N) for c in self.classes_])
        self.log_likelihoods_ = np.zeros((len(self.classes_), V))
        for k, c in enumerate(self.classes_):
            word_counts = X[y == c].sum(axis=0)           # (V,)
            total = word_counts.sum() + self.alpha * V
            self.log_likelihoods_[k] = np.log((word_counts + self.alpha) / total)

    def predict_log_proba(self, X: np.ndarray) -> np.ndarray:
        # (N, V) @ (V, C) + (C,) = (N, C)
        return X @ self.log_likelihoods_.T + self.log_priors_

    def predict(self, X: np.ndarray) -> np.ndarray:
        return self.classes_[np.argmax(self.predict_log_proba(X), axis=1)]
